=CLEAN_DATA(data_range, algorithm_type, confidence_threshold)

// Advanced duplicate detection with fuzzy matching
=CLEAN_DATA(A2:D100, "DUPLICATE_DETECTION", 0.85)

// Auto-fill missing values based on patterns
=CLEAN_DATA(B2:C100, "MISSING_VALUE_IMPUTATION", 0.90)

// Remove outliers based on statistical methods
=CLEAN_DATA(D2:D100, "OUTLIER_REMOVAL", 0.95)

// Apply multiple cleaning steps
=CLEAN_DATA(A2:E100, "FULL_CLEANUP", 0.92)

// Returns: Cleaned data array + summary report

=TREND_ANALYZE(data_series, mode, significance_level)

// Auto-detect trend type and analyze
=TREND_ANALYZE(B2:B365, "AUTO_DETECT", 0.95)

// Multi-variate trend analysis
=TREND_ANALYZE(B2:E365, "MULTIVARIATE", 0.90)

// Seasonal decomposition
=TREND_ANALYZE(A2:B365, "SEASONAL", 0.95)

// Force linear trend
=TREND_ANALYZE(B2:B100, "LINEAR", 0.95)

// Returns: [Trend Type, Slope, Intercept, R² value, Confidence Intervals, Predictions]

=FORECAST_DEMAND(
